mapper.select:
SELECT seller_id as "id", store_name as "storeName", business_name as "businessName", contact_email as "email", contact_phone as "phone", CASE WHEN gst_verified = true AND pan_verified = true THEN 'VERIFIED' ELSE 'PENDING' END as "kycStatus", seller_status as "stateId", tier as "tier", health_score as "healthScore", rating as "rating", fulfillment_rate as "fulfillmentRate", active_listings as "activeListings", gmv_30d as "gmv30d", orders_30d as "orders30d", CASE WHEN seller_status = 'ACTIVE' THEN true ELSE false END as "active", active_date as "createdAt" FROM hm_query.seller_dashboard_flat
AND LOWER(store_name) LIKE LOWER(CONCAT('%', #{storeName}, '%')) AND gst_verified = CASE WHEN #{kycStatus} = 'VERIFIED' THEN true ELSE false END AND seller_status = CASE WHEN #{active} = true THEN 'ACTIVE' ELSE seller_status END AND seller_status = #{stateId} AND business_name LIKE CONCAT('%', #{businessName}, '%') AND tier = #{tier} AND (store_name LIKE CONCAT('%', #{q}, '%') OR business_name LIKE CONCAT('%', #{q}, '%') OR contact_email LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT seller_id as "sellerId", business_name as "businessName", store_name as "storeName", health_score as "healthScore", rating as "rating", fulfillment_rate as "fulfillmentRate", dispatch_sla_pct as "dispatchSlaPct", delivery_sla_pct as "deliverySlaPct", return_rate as "returnRate", response_time_hours as "responseTimeHours", cancellation_rate as "cancellationRate", violations_count as "violationsCount", orders_30d as "orderCount", gmv_30d as "gmv30d", revenue_30d as "revenue30d", avg_lead_time_days as "avgLeadTimeDays" FROM hm_query.seller_dashboard_flat
AND seller_id = #{sellerId}
ORDER BY rating DESC ${pagination}
